// src/components/InternshipModal.jsx
import React, { useState, useEffect } from 'react';

export default function InternshipModal({ isOpen, onClose, onSave, editingInternship }) {
  const [form, setForm] = useState({
    title: '',
    company: '',
    category: '',
    location: '',
    mode: '',
    description: '',
  });

  useEffect(() => {
    if (editingInternship) {
      setForm(editingInternship);
    } else {
      setForm({
        title: '',
        company: '',
        category: '',
        location: '',
        mode: '',
        description: '',
      });
    }
  }, [editingInternship]);

  const handleChange = (e) =>
    setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = (e) => {
    e.preventDefault();
    onSave(form);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50">
      <div className="bg-white p-6 rounded-xl w-[90%] max-w-md shadow-lg">
        <h2 className="text-xl font-semibold mb-4">
          {editingInternship ? 'Edit Internship' : 'Add Internship'}
        </h2>
        <form onSubmit={handleSubmit} className="space-y-3">
          {['title', 'company', 'category', 'location', 'mode', 'description'].map((field) => (
            <input
              key={field}
              type="text"
              name={field}
              placeholder={field[0].toUpperCase() + field.slice(1)}
              value={form[field]}
              onChange={handleChange}
              required
              className="w-full px-3 py-2 border rounded"
            />
          ))}

          <div className="flex justify-end gap-2">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-1 border rounded bg-gray-200"
            >
              Cancel
            </button>
            <button type="submit" className="px-4 py-1 bg-blue-600 text-white rounded">
              Save
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
